#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maximalRectangle(vector<vector<char>>& matrix) {
        if (matrix.empty()) {
            return 0;
        }

        int m = matrix.size(), n = matrix[0].size();
        vector<int> height(n + 1, 0);
        int ans = 0;

        for (const auto& row : matrix) {
            for (int i = 0; i < n; ++i) {
                height[i] = row[i] == '1' ? height[i] + 1 : 0;
            }
            stack<int> stk;
            for (int i = 0; i <= n; ++i) {
                while (!stk.empty() && height[i] < height[stk.top()]) {
                    int h = height[stk.top()]; stk.pop();
                    int w = stk.empty() ? i : i - stk.top() - 1;
                    ans = max(ans, h * w);
                }
                stk.push(i);
            }
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    cin >> m >> n;
    vector<vector<char>> matrix(m, vector<char>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> matrix[i][j];
        }
    }
    Solution sol;
    int ans = sol.maximalRectangle(matrix);
    cout << ans << "\n";
    return 0;
}
